  2→ * ContactRepository tests
  3→ *
  4→ * Uses tsx for test execution. Creates a test contact in dev.db.
  5→ */
  6→
  7→import { describe, it } from 'node:test';
  8→import assert from 'node:assert';
  9→import { contacts } from './contacts.js';
 10→import { prisma } from './prisma.js';
 11→
 12→describe('ContactRepository', { concurrency: false }, () => {
 13→  // Track created test contact for cleanup
 14→  let testContactId: string;
 15→
 16→  it('should create a new contact', async () => {
 17→    // Ensure clean state before first test
 18→    await prisma.contact.deleteMany({
 19→      where: { email: 'test@example.com' },
 20→    });
 21→
 22→    const contact = await contacts.create({
 23→      type: 'person',
 24→      firstName: 'Test',
 25→      lastName: 'User',
 26→      email: 'test@example.com',
 27→      phone: '+79991234567',
 28→      status: 'active',
 29→      tags: ['test', 'tsx-test'],
 30→    });
 31→
 32→    assert.ok(contact, 'Contact should be created');
 33→    assert.ok(contact.id, 'Contact should have an ID');
 34→    assert.strictEqual(contact.email, 'test@example.com');
 35→    assert.strictEqual(contact.type, 'person');
 36→    testContactId = contact.id;
 37→  });
 38→
 39→  it('should find contact by ID', async () => {
 40→    const contact = await contacts.findUnique(testContactId);
 41→    assert.ok(contact, 'Contact should be found');
 42→    assert.strictEqual(contact?.id, testContactId);
 43→    assert.strictEqual(contact?.email, 'test@example.com');
 44→  });
 45→
 46→  it('should find contact by email', async () => {
 47→    const contact = await contacts.findByEmail('test@example.com');
 48→    assert.ok(contact, 'Contact should be found by email');
 49→    assert.strictEqual(contact?.id, testContactId);
 50→  });
 51→
 52→  it('should find many contacts', async () => {
 53→    const list = await contacts.findMany({
 54→      where: { type: 'person' },
 55→      orderBy: { createdAt: 'desc' },
 56→    });
 57→    assert.ok(Array.isArray(list), 'Result should be an array');
 58→    assert.ok(list.length > 0, 'Array should have items');
 59→    assert.strictEqual(list[0].email, 'test@example.com');
 60→  });
 61→
 62→  it('should update a contact', async () => {
 63→    const updated = await contacts.update(testContactId, {
 64→      phone: '+79997654321',
 65→      notes: 'Updated via test',
 66→    });
 67→    assert.strictEqual(updated.phone, '+79997654321');
 68→    assert.strictEqual(updated.notes, 'Updated via test');
 69→  });
 70→
 71→  it('should soft delete a contact', async () => {
 72→    const deleted = await contacts.softDelete(testContactId);
 73→    assert.ok(deleted.deletedAt, 'deletedAt should be set');
 74→
 75→    // Should not be found via normal queries
 76→    const notFound = await contacts.findUnique(testContactId);
 77→    assert.strictEqual(notFound, null, 'Soft-deleted contact should not be found');
 78→
 79→    // But should still exist in database
 80→    const stillExists = await prisma.contact.findUnique({
 81→      where: { id: testContactId },
 82→    });
 83→    assert.ok(stillExists, 'Contact should still exist in DB');
 84→    assert.ok(stillExists?.deletedAt, 'Contact should have deletedAt set');
 85→  });
 86→
 87→  it('should check email existence', async () => {
 88→    // Create fresh contact for existence test
 89→    const fresh = await contacts.create({
 90→      type: 'person',
 91→      firstName: 'Fresh',
 92→      lastName: 'Test',
 93→      email: 'freshtest@example.com',
 94→    });
 95→
 96→    const exists = await contacts.existsByEmail('freshtest@example.com');
 97→    assert.strictEqual(exists, true, 'Email should exist');
 98→
 99→    const notExists = await contacts.existsByEmail('nonexistent@example.com');
100→    assert.strictEqual(notExists, false, 'Nonexistent email should not exist');
101→
102→    // Cleanup
103→    await prisma.contact.delete({ where: { id: fresh.id } });
104→  });
105→
106→  it('should count contacts', async () => {
107→    const count = await contacts.count();
108→    assert.strictEqual(typeof count, 'number', 'Count should be a number');
109→    assert.ok(count >= 0, 'Count should be non-negative');
110→  });
111→
112→  // Final cleanup
113→  it('cleanup test data', async () => {
114→    if (testContactId) {
115→      await prisma.contact.deleteMany({
116→        where: { id: testContactId },
117→      });
118→    }
119→    await prisma.$disconnect();
120→  });
121→});
